javascript: class SpringAnimation {
    constructor() {
        this.ball = document.querySelector('.data-util');
        this.gravity = 0.1;
        this.velocity = 0;
        this.maxVelocity = 30;
        this.minVelocity = 0;
        this.damping = 0.995;
    }

    animate() {
        this.velocity += this.gravity;
        if (this.velocity > this.maxVelocity || this.velocity < this.minVelocity) this.velocity *= this.damping;
        this.ball.style.transform = `translateY(${this.velocity}px) scale(1.1) rotate(-${(30 - this.velocity * 0.1)}deg)`;
        requestAnimationFrame(() => this.animate());
    }

    init() {
        this.animate();
    }
}
new SpringAnimation().init();
